import React, { useState } from 'react';
import '../styles/NotesListPage.css';

export default function NotesListPage() {
  const [notes, setNotes] = useState([
    { id: 1, title: 'React Hooks Explained', date: '2025-02-10', status: 'published', tags: ['React', 'JavaScript'] },
    { id: 2, title: 'CSS Grid Mastery', date: '2025-02-09', status: 'published', tags: ['CSS', 'Web Design'] },
    { id: 3, title: 'Node.js Best Practices', date: '2025-02-08', status: 'draft', tags: ['Node.js', 'Backend'] },
    { id: 4, title: 'Database Design Patterns', date: '2025-02-07', status: 'published', tags: ['Database', 'Design'] },
  ]);

  const [filter, setFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredNotes = notes.filter((note) => {
    const matchesFilter = filter === 'all' || note.status === filter;
    const matchesSearch = note.title.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  return (
    <div className="notes-list-container">
      <div className="notes-header">
        <h1>My Notes</h1>
        <button className="btn-create">+ Create New Note</button>
      </div>

      <div className="notes-controls">
        <input
          type="text"
          placeholder="Search notes..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />

        <div className="filter-buttons">
          <button
            className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            All
          </button>
          <button
            className={`filter-btn ${filter === 'published' ? 'active' : ''}`}
            onClick={() => setFilter('published')}
          >
            Published
          </button>
          <button
            className={`filter-btn ${filter === 'draft' ? 'active' : ''}`}
            onClick={() => setFilter('draft')}
          >
            Drafts
          </button>
        </div>
      </div>

      <div className="notes-list">
        {filteredNotes.length === 0 ? (
          <div className="no-notes">
            <p>No notes found</p>
          </div>
        ) : (
          filteredNotes.map((note) => (
            <div key={note.id} className="note-item">
              <div className="note-info">
                <h3>{note.title}</h3>
                <div className="note-meta">
                  <span className="note-date">{note.date}</span>
                  <span className={`note-status ${note.status}`}>
                    {note.status}
                  </span>
                </div>
                <div className="note-tags">
                  {note.tags.map((tag) => (
                    <span key={tag} className="tag">
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
              <div className="note-actions">
                <button className="btn-view">View</button>
                <button className="btn-edit">Edit</button>
                <button className="btn-share">Share</button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
